export interface ShipmentSentPayload {
  to: string;
  customerName: string;
  customerEmail?: string;
  orderNumber: string;
  trackingNumber: string;
  cargoCompany?: string;
  siteName: string;
}

export async function sendShipmentSent(payload: ShipmentSentPayload): Promise<SendEmailResult> {
  const r = await resolveTemplate("shipmentSent", {
    customer_name: payload.customerName,
    customer_email: payload.customerEmail ?? payload.to,
    order_number: payload.orderNumber,
    order_total: "",
    tracking_number: payload.trackingNumber,
    cargo_company: payload.cargoCompany ?? "",
    site_name: payload.siteName,
  });
  return sendEmail({ to: payload.to, subject: r.subject, html: await buildLayout({ bodyHtml: r.bodyHtml }) });
}

/** @deprecated {@link sendShipmentSent} kullanın */
export async function sendOrderShipped(
  payload: ShipmentSentPayload | Omit<ShipmentSentPayload, "cargoCompany">,
): Promise<SendEmailResult> {
  const cargoCompany =
    "cargoCompany" in payload && payload.cargoCompany !== undefined && payload.cargoCompany !== ""
      ? payload.cargoCompany
      : "—";
  return sendShipmentSent({ ...payload, cargoCompany });
}

